import React, { useState, useEffect } from "react";

function RouteForm({ onNewRoute }) {
  const [departure, setDeparture] = useState("");
  const [arrival, setArrival] = useState("");
  const [stops, setStops] = useState("");
  const [stations, setStations] = useState([]);

  useEffect(() => {
    fetch("http://localhost:5050/stations")
      .then(res => res.json())
      .then(setStations)
      .catch(console.error);
  }, []);

  const handleSubmit = async e => {
    e.preventDefault();
    const stopsArr = stops.split(",").map(s => s.trim()).filter(Boolean);

    const res = await fetch("http://localhost:5050/routes", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ departure, arrival, stops: stopsArr })
    });
    const data = await res.json();
    if (res.ok) {
      onNewRoute(data);
      setDeparture(""); setArrival(""); setStops("");
    } else alert(data.error);
  };

  return (
    <form onSubmit={handleSubmit}>
      <select value={departure} onChange={e => setDeparture(e.target.value)}>
        <option value="">Станция отправления</option>
        {stations.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
      </select>
      <select value={arrival} onChange={e => setArrival(e.target.value)}>
        <option value="">Станция прибытия</option>
        {stations.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
      </select>
      <input
        type="text"
        placeholder="Остановочные пункты (через запятую)"
        value={stops}
        onChange={e => setStops(e.target.value)}
      />
      <button type="submit">Добавить маршрут</button>
    </form>
  );
}

export default RouteForm;
